void TensoToAffineLoweringPass::runOnOperation() {
 // The first thing to define is the conversion target.
 MLIRContext &ctx = getContext();
 mlir::ConversionTarget target(ctx);

 // `Affine`, `Arith`, `Func`, and `MemRef` dialects.
 target.addLegalDialect<affine::AffineDialect, arith::ArithDialect,
 func::FuncDialect, memref::MemRefDialect>();

 // We also define the Tenso dialect as Illegal so that the conversion will fail
 // if any of these operations are *not* converted. Given that we actually want
 // a partial lowering, we explicitly mark the Tenso operations that don't want
 // to lower, `tenso.print`, as *legal*. `tenso.print` will still need its operands
 // to be updated though (as we convert from TensorType to MemRefType), so we
 // only treat it as `legal` if its operands are legal.
 target.addIllegalDialect<TensoDialect>();
 target.addDynamicallyLegalOp<tenso::PrintOp>([](tenso::PrintOp op) {
 return llvm::none_of(op->getOperandTypes(), [](Type t) {
 return llvm::isa<TensorType>(t);
 });
 });
 ...
}
```

```
struct TransposeOpLowering : public OpConversionPattern<tenso::TransposeOp> {
 using OpConversionPattern<tenso::TransposeOp>::OpConversionPattern;

 LogicalResult matchAndRewrite(tenso::TransposeOp op, OpAdaptor adaptor,
 ConversionPatternRewriter &rewriter) const final {
 Location loc = op.getLoc();
 Value input = adaptor.getInput();

 if (!llvm::isa<MemRefType>(input.getType()))
 return rewriter.notifyMatchFailure(op, "expected memref input");

 lowerOpToLoops(op, rewriter, [&](OpBuilder &b, ValueRange ivs) -> Value {

 // Transpose the elements by generating a load from the
 // reverse indices.
 SmallVector<Value, 2> rev(llvm::reverse(ivs));
 return affine::AffineLoadOp::create(b, loc, input, rev);
 });
 return success();
 }
};
```

