For more advanced usage in modules:

```
import torch
import ttnn
from bos_metal import op

class LinearOp(op.Operation):
 def __init__(self, in_features, out_features):
 super().__init__()
 self.weight = op.BaseParameter(
 torch.randn(out_features, in_features),
 map_func=lambda x: self._map_func(x, transpose=True)
 )
 self.bias = op.BaseParameter(
 torch.zeros(out_features),
 map_func=lambda x: self._map_func(x, transpose=False)
 )

 def _map_func(self, x: torch.Tensor, transpose=False):
 if transpose:
 x = x.T
 return ttnn.from_torch(x, device=self.device)

 def forward(self, x):
 return x @ self.weight.ttnn_data + self.bias.ttnn_data
```

