```
// 1 divide per dim; remainder without %
static inline uint32_t flip_id_fast_strides(
 uint32_t in_id,
 uint32_t page_rank,
 uint32_t flip_mask,
 const uint32_t* page_sizes,
 const uint32_t* page_strides
) {

 if (flip_mask == 0) //only flip last dim or not flip at all
 {
 return in_id;
 }

 if (flip_mask == (1u << (page_rank - 1))) { // flip the second last dim only
 const uint32_t sz = page_sizes[page_rank - 1];
 const uint32_t q = in_id / sz;
 const uint32_t r = in_id - q * sz;
 return q * sz + (sz - 1u - r);
 }

 uint32_t t = in_id;
 uint32_t out_id = 0;

 for (int d = (int)page_rank - 1; d >= 0; --d) {
 uint32_t sz = page_sizes[d];
 uint32_t q = t / sz;
 uint32_t r = t - q * sz;
 if (flip_mask & (1u << (uint32_t)d)) {
 r = (sz - 1u) - r;
 }
 out_id += r * page_strides[d];
 t = q;
 }

 return out_id;
}
