class InvocationBuffer:
 def __init__(self, device, target_cq_id: int):
 self.device = device
 self.target_cq_id = target_cq_id
 self._blocks = []
 self._tls = threading.local()

 @contextmanager
 def add_block(self, priority=0):
 ops = []
 self._tls.ops = ops

 def defer(fn):
 ops.append(fn) # Lazily queue operations

 try:
 yield defer
 finally:
 self._blocks.append((priority, ops))
 self._tls.ops = None

 def flush(self, num_blocks=99):
 self._blocks.sort(key=lambda b: b[0]) # Priority order
 for i, (priority, ops) in enumerate(self._blocks[:num_blocks]):
 for op in ops:
 op() # Execute all deferred operations
 del self._blocks[:num_blocks]
```

Each **block** represents a set of deferred operations to be executed later. Developers can enqueue work using the `defer()` function within a context block.

