```
module @SimpleConv2dModelv1 {
 ttcore.device @default_device = <workerGrid = 4x5>

 func.func @forward(
 %input : tensor<1x64x64x64xbf16, dram_interleaved>,
 %weight : tensor<64x64x1x1xbf16, system_memory>,
 %bias : tensor<1x1x1x64xbf16, dram_interleaved>
 ) -> tensor<1x64x64x64xbf16, dram_interleaved> {

 // ---- Explicit buffer materialization ----
 %in_buf = ttnn.empty(shape=1x64x64x64, dram)
 %tmp_buf = ttnn.empty(shape=1x1x4096x64, dram)

 // ---- Layout canonicalization ----
 %p0 = ttnn.permute %input // NCHW → NHWC
 %r0 = ttnn.reshape %p0 // flatten H*W

 // ---- Weight layout conversion ----
 %w0 = ttnn.to_layout %weight // system → DRAM, tile layout

 // ---- Core compute ----
 %conv = ttnn.conv2d(
 %r0, %w0, %bias, %device
 ) {
 kernel = 1x1,
 in_channels = 64,
 out_channels = 64,
 stride = 1x1,
 padding = 0,
 dtype = bf16
 }

 // ---- Activation ----
 %relu = ttnn.relu %conv

 // ---- Output reformatting ----
 %r1 = ttnn.reshape %relu
 %out = ttnn.permute %r1 // NHWC → NCHW

 return %out
 }
}
```

