```
reshardPropagation:
 for each edge (producer → consumer) in opSchedule:
 // Get configs for producer and consumer
 producerConfigs = opConfigCandidates[producer]
 consumerConfigs = opConfigCandidates[consumer]

 // Get layouts
 producerOutputLayouts = unique(
 getOutputLayout(config)
 for config in producerConfigs
 )
 consumerInputLayouts = unique(
 getInputLayout(config)
 for config in consumerConfigs
 )

 // Reshard edges propagation
 for layoutA in producerOutputLayouts:
 for layoutB in consumerInputLayouts:

 if layoutA == layoutB:
 reshardType = NO_OP
 reshardCandidates[edge].append(layoutA -> layoutB, NO_OP)
 else:
 result = op_model::validate_layout_conversion(layoutA, layoutB)

 if result.success:
 reshardCandidates[edge].append(layoutA -> layoutB, AVAILABLE)
 else:
 reshardCandidates[edge].append(layoutA -> layoutB, NONE)
